const watchlist = [
  { symbol: 'AAPL', name: 'Apple Inc.', alert_drop_pct: -2, alert_rise_pct: 3, max_price: 200, min_price: 170 },
  { symbol: 'NVDA', name: 'NVIDIA Corp.', alert_drop_pct: -3, alert_rise_pct: 5, max_price: 950, min_price: 700 },
  { symbol: 'TSLA', name: 'Tesla Inc.', alert_drop_pct: -4, alert_rise_pct: 6, max_price: 300, min_price: 180 },
  { symbol: 'MSFT', name: 'Microsoft Corp.', alert_drop_pct: -2, alert_rise_pct: 3, max_price: 450, min_price: 380 },
  { symbol: 'SPY', name: 'S&P 500 ETF', alert_drop_pct: -1.5, alert_rise_pct: 2, max_price: 560, min_price: 480 }
];
return watchlist.map(stock => ({ json: stock }));

const result = $input.item.json.chart?.result?.[0];
if (!result) return [{ json: { error: 'No data', symbol: $('Load Watchlist').item.json.symbol } }];
const meta = result.meta;
const currentPrice = meta.regularMarketPrice;
const prevClose = meta.chartPreviousClose || meta.previousClose;
const change = currentPrice - prevClose;
const changePct = parseFloat(((change / prevClose) * 100).toFixed(2));
const closes = result.indicators?.quote?.[0]?.close || [];
const recentCloses = closes.filter(c => c !== null).slice(-5);
const fiveDayChange = recentCloses.length > 1
  ? parseFloat((((recentCloses[recentCloses.length-1] - recentCloses[0]) / recentCloses[0]) * 100).toFixed(2))
  : 0;
const watchItem = $('Load Watchlist').item.json;
return [{
  json: {
    symbol: watchItem.symbol,
    name: watchItem.name,
    current_price: currentPrice,
    prev_close: prevClose,
    change: parseFloat(change.toFixed(2)),
    change_pct: changePct,
    day_high: meta.regularMarketDayHigh,
    day_low: meta.regularMarketDayLow,
    volume: meta.regularMarketVolume,
    avg_volume: meta.averageDailyVolume3Month,
    volume_ratio: meta.averageDailyVolume3Month ? parseFloat((meta.regularMarketVolume / meta.averageDailyVolume3Month).toFixed(2)) : null,
    five_day_change_pct: fiveDayChange,
    fetched_at: new Date().toISOString(),
    alert_drop_pct: watchItem.alert_drop_pct,
    alert_rise_pct: watchItem.alert_rise_pct,
    max_price: watchItem.max_price,
    min_price: watchItem.min_price
  }
}];

const d = $json;
const alerts = [];
if (d.change_pct <= d.alert_drop_pct) alerts.push({ type: 'DROP', severity: 'HIGH', message: `${d.symbol} dropped ${d.change_pct}% (threshold: ${d.alert_drop_pct}%)` });
if (d.change_pct >= d.alert_rise_pct) alerts.push({ type: 'SPIKE', severity: 'MEDIUM', message: `${d.symbol} surged +${d.change_pct}% (threshold: +${d.alert_rise_pct}%)` });
if (d.current_price >= d.max_price) alerts.push({ type: 'PRICE_HIGH', severity: 'HIGH', message: `${d.symbol} hit ceiling $${d.current_price} (max: $${d.max_price})` });
if (d.current_price <= d.min_price) alerts.push({ type: 'PRICE_LOW', severity: 'HIGH', message: `${d.symbol} hit floor $${d.current_price} (min: $${d.min_price})` });
if (d.volume_ratio && d.volume_ratio >= 2.5) alerts.push({ type: 'VOLUME_SPIKE', severity: 'MEDIUM', message: `${d.symbol} volume is ${d.volume_ratio}x normal` });
return [{ json: { ...d, alerts, has_alerts: alerts.length > 0, any_high_severity: alerts.some(a => a.severity === 'HIGH') } }];

const raw = $input.item.json.content[0].text.trim();
const analysis = JSON.parse(raw.replace(/```json?\n?/g, '').replace(/```$/g, '').trim());
const d = $('Check Alert Conditions').item.json;
const msg = [
  `STOCK ALERT — ${d.symbol} (${d.name})`,
  `Price: $${d.current_price} (${d.change_pct > 0 ? '+' : ''}${d.change_pct}% today)`,
  ``,
  `AI Analysis: ${analysis.summary}`,
  `Recommended: ${analysis.recommended_action} | Confidence: ${analysis.confidence}`,
  `Risk: ${analysis.key_risk}`,
  `Next Step: ${analysis.next_step}`,
  ``,
  `Triggered:`,
  ...d.alerts.map(a => `  [${a.severity}] ${a.message}`),
  ``,
  `${new Date().toLocaleString()} | Final decision is YOURS`
].join('\n');
console.log(msg);
return [{ json: { ...d, ai_analysis: analysis, alert_message: msg, requires_human_approval: true } }];
